import osimport base64import streamlit as stfrom langchain_google_genai import ChatGoogleGenerativeAIfrom langchain_community.embeddings import HuggingFaceEmbeddingsfrom langchain_community.vectorstores import Chromafrom langchain_core.prompts import ChatPromptTemplate, MessagesPlaceholderfrom langchain_core.runnables import RunnablePassthroughfrom langchain_core.output_parsers import StrOutputParserfrom langchain_core.messages import HumanMessage, AIMessage# --- API KEY (Exposed - Best practice to use st.secrets for production) ---os.environ["GOOGLE_API_KEY"] = "AIzaSyCcTkFjc--jiN8twNQ9SVxamsgXOqJLSho"# ─── PAGE CONFIGURATION ──────────────────────────────────────st.set_page_config(    page_title="Virtual Try-All AI | Jamal Hassan",    page_icon="🛍️",    layout="centered",     initial_sidebar_state="expanded")# ─── CUSTOM CSS ANIMATIONS & STYLING ─────────────────────────st.markdown("""<style>    /* Profile Header Styling (NEW ENLARGED SIZE) */    .profile-container {        display: flex;        align-items: center;        justify-content: flex-end;         gap: 20px; /* Increased gap */        padding: 15px 0px; /* Increased padding */        margin-bottom: -30px;     }    .profile-img {        width: 110px; /* Increased significantly from 60px */        height: 110px; /* Increased significantly from 60px */        border-radius: 50%;         border: 4px solid rgba(255, 255, 255, 0.3); /* Thicker border */        object-fit: cover;         box-shadow: 0 6px 15px rgba(0,0,0,0.2); /* Enhanced shadow */        transition: all 0.3s ease;    }    .profile-img:hover {        transform: scale(1.05) rotate(3deg); /* Slightly less scaling, added rotation */        box-shadow: 0 10px 25px rgba(255, 75, 75, 0.4);    }    .profile-text-container {        text-align: right;    }    .profile-name {        font-size: 2rem; /* Increased significantly from 1.2rem */        font-weight: 800; /* Extra bold */        background: -webkit-linear-gradient(#eee, #aaa);        -webkit-background-clip: text;        -webkit-text-fill-color: transparent;        margin: 0;        padding: 0;    }    .profile-title {        font-size: 1rem; /* Increased slightly */        color: #aaa; /* Lighter text */        margin: 0;        padding: 0;        margin-top: -3px;        font-weight: 400;        letter-spacing: 1px;    }    /* Highlight Top Left Logo area (NEW HIGHLIGHT) */    .logo-header-container {        background: rgba(255, 255, 255, 0.05); /* Subtle background */        border: 1px solid rgba(255, 75, 75, 0.3); /* Highlight border color */        border-radius: 15px; /* Pill shape */        padding: 15px 25px;        margin-bottom: 25px;        box-shadow: 0 4px 15px rgba(255, 75, 75, 0.15); /* Soft glow shadow */        transition: all 0.3s ease;        text-align: left;    }    .logo-header-container:hover {        box-shadow: 0 6px 20px rgba(255, 75, 75, 0.25); /* Enhanced glow on hover */        background: rgba(255, 255, 255, 0.08); /* Slightly brighter background */        transform: scale(1.02);    }    /* Chat Message Hover Animation */    .stChatMessage {        transition: all 0.3s ease-in-out;        border-radius: 12px;        padding: 10px;        margin-bottom: 10px;    }    .stChatMessage:hover {        transform: translateY(-3px);        box-shadow: 0 6px 12px rgba(0, 0, 0, 0.1);        background-color: rgba(150, 150, 150, 0.05);    }        /* Glowing Button Animation */    .stButton>button {        transition: all 0.3s ease;        border-radius: 25px;        border: 1px solid #ff4b4b;        color: #ff4b4b;        font-weight: bold;    }    .stButton>button:hover {        transform: scale(1.05);        box-shadow: 0 0 15px rgba(255, 75, 75, 0.4);        background-color: #ff4b4b;        color: white;    }        /* Title Gradient */    .custom-title {        font-size: 2.5rem; /* slightly adjusted down for the logo badge */        font-weight: 800;        background: -webkit-linear-gradient(45deg, #FF4B2B, #FF416C);        -webkit-background-clip: text;        -webkit-text-fill-color: transparent;        margin: 0; /* Reset margin inside container */        padding: 0;    }        /* Source Expander Hover */    .streamlit-expanderHeader:hover {        color: #ff4b4b !important;        transition: color 0.3s ease;    }</style>""", unsafe_allow_html=True)# ─── CACHED BACKEND INITIALIZATION (PURE LCEL) ───────────────@st.cache_resource(show_spinner="Booting AI Core...")def load_rag_chain():    llm = ChatGoogleGenerativeAI(        model="gemini-2.5-flash",        google_api_key=os.environ.get("GOOGLE_API_KEY"),        temperature=0.3    )    embeddings_hf = HuggingFaceEmbeddings(model_name="all-MiniLM-L6-v2")    vector_store = Chroma(        persist_directory="./chroma_db",         embedding_function=embeddings_hf    )    retriever = vector_store.as_retriever(search_kwargs={"k": 4})    def format_docs(docs):        return "\n\n".join(doc.page_content for doc in docs)    condense_prompt = ChatPromptTemplate.from_messages([        ("system", "Given a chat history and the latest user question, formulate a standalone question. Do NOT answer the question, just reformulate it if needed and otherwise return it as is."),        MessagesPlaceholder(variable_name="chat_history"),        ("human", "{question}")    ])        standalone_question_chain = condense_prompt | llm | StrOutputParser()    def get_standalone_question(input_dict):        if input_dict.get("chat_history"):            return standalone_question_chain.invoke(input_dict)        return input_dict["question"]    qa_prompt = ChatPromptTemplate.from_messages([        ("system", "You are a highly intelligent AI expert in the Virtual Try-All domain. Use the following pieces of retrieved context to answer the question elegantly. If you don't know the answer, politely say you don't know.\n\nContext: {context}"),        MessagesPlaceholder(variable_name="chat_history"),        ("human", "{question}")    ])    rag_chain = (        RunnablePassthrough.assign(standalone_question=get_standalone_question)        | RunnablePassthrough.assign(docs=lambda x: retriever.invoke(x["standalone_question"]))        | RunnablePassthrough.assign(context=lambda x: format_docs(x["docs"]))        | RunnablePassthrough.assign(answer=(qa_prompt | llm | StrOutputParser()))    )        return rag_chain# Load the chaintry:    rag_chain = load_rag_chain()except Exception as e:    st.error(f"Failed to load the AI pipeline. Error: {e}")    st.stop()# ─── MAIN UI LAYOUT & PROFILE HEADER ─────────────────────────# Absolute Mac path to your image in Downloadslocal_image_path = "/Users/m12021/Downloads/Jamal.jpeg" def get_base64_of_bin_file(bin_file):    try:        with open(bin_file, 'rb') as f:            data = f.read()        return base64.b64encode(data).decode()    except Exception as e:        # Silently fail if file not found, fallback handles it        return "" base64_image = get_base64_of_bin_file(local_image_path)if base64_image:    MY_PICTURE_URL = f"data:image/jpeg;base64,{base64_image}"else:    # Modern generic icon if local photo isn't found    MY_PICTURE_URL = "https://cdn-icons-png.flaticon.com/512/3135/3135715.png"# Inject the profile HTMLst.markdown(f"""<div class="profile-container">    <div class="profile-text-container">        <div class="profile-name">Jamal Hassan</div>        <div class="profile-title">AI Project Lead</div>    </div>    <img src="{MY_PICTURE_URL}" class="profile-img"></div>""", unsafe_allow_html=True)# Main Title (Highlighted Logo Area)st.markdown("""<div class="logo-header-container">    <p class="custom-title">🛍️ Virtual Try-All Assistant</p></div>""", unsafe_allow_html=True)st.caption("⚡ Powered by Gemini 2.5 Flash & LangChain")# ─── SIDEBAR ─────────────────────────────────────────────────with st.sidebar:    st.image("https://cdn-icons-png.flaticon.com/512/6083/6083162.png", width=80)    st.header("⚙️ System Telemetry")        col1, col2 = st.columns(2)    col1.metric("LLM Core", "Gemini 2.5", "Online")    col2.metric("Embeddings", "MiniLM", "Active")    st.metric("Vector Database", "Chroma DB", "Connected")        st.divider()    st.markdown("### 💡 Try asking:")    st.markdown("- *What is Diffuse to Choose?*")    st.markdown("- *How does it compare to PBE?*")    st.markdown("- *What are the main use cases?*")        st.divider()    if st.button("🗑️ Clear Chat History", use_container_width=True):        st.session_state.messages = []        st.session_state.langchain_history = []        st.rerun()# ─── SESSION STATE MANAGEMENT ────────────────────────────────if "messages" not in st.session_state or len(st.session_state.messages) == 0:    st.session_state.messages = [{        "role": "assistant",         "content": "👋 **Welcome!** I have fully analyzed the `VirtualTryAll` documents. Ask me anything about the architecture, use cases, or comparisons!"    }]if "langchain_history" not in st.session_state:    st.session_state.langchain_history = []# ─── DRAW CHAT HISTORY ───────────────────────────────────────for msg in st.session_state.messages:    with st.chat_message(msg["role"]):        st.markdown(msg["content"])        if "sources" in msg and msg["sources"]:            with st.expander("📚 View Document Sources"):                for i, doc in enumerate(msg["sources"]):                    page = doc.metadata.get("page", "Unknown")                    st.info(f"**Source {i+1} (Page {page}):**\n\n{doc.page_content[:250]}...", icon="📄")# ─── HANDLE USER INPUT ───────────────────────────────────────if prompt := st.chat_input("Ask a question about DTC..."):        with st.chat_message("user"):        st.markdown(prompt)        st.session_state.messages.append({"role": "user", "content": prompt})        with st.chat_message("assistant"):        with st.spinner("🤖 Consulting the vector database..."):                        response = rag_chain.invoke({                "question": prompt,                "chat_history": st.session_state.langchain_history            })                        answer = response["answer"]            source_docs = response["docs"]                        st.markdown(answer)                        if source_docs:                with st.expander("📚 View Document Sources"):                    for i, doc in enumerate(source_docs):                        page = doc.metadata.get("page", "Unknown")                        st.info(f"**Source {i+1} (Page {page}):**\n\n{doc.page_content[:250]}...", icon="📄")                st.session_state.messages.append({        "role": "assistant",         "content": answer,        "sources": source_docs    })        st.session_state.langchain_history.extend([        HumanMessage(content=prompt),        AIMessage(content=answer)    ])